import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

import DeanLayout from "../../layouts/DeanLayout";

import {
  getFacultySubmissionById
} from "../../api/deanApi";

import facultyQuestions from "../../data/facultyQuestions";

function DeanFacultyView() {

  const { id } = useParams();

  const navigate = useNavigate();

  const [submission, setSubmission] =
    useState(null);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadSubmission();

  }, []);

  const loadSubmission =
    async () => {

      try {

        const res =
          await getFacultySubmissionById(id);

        setSubmission(
          res.data.submission
        );

      }

      catch (error) {

        console.error(error);

      }

      finally {

        setLoading(false);

      }

    };

  // ============================
  // LOADING
  // ============================

  if (loading) {

    return (

      <DeanLayout>

        <div
          style={{
            padding: "50px",
            textAlign: "center",
            fontSize: "22px",
            fontWeight: "600"
          }}
        >

          Loading Faculty Submission...

        </div>

      </DeanLayout>

    );

  }

  // ============================
  // NOT FOUND
  // ============================

  if (!submission) {

    return (

      <DeanLayout>

        <div
          style={{
            padding: "50px",
            textAlign: "center",
            color: "red",
            fontSize: "22px"
          }}
        >

          Submission Not Found

        </div>

      </DeanLayout>

    );

  }

  // ============================
  // ANSWER SEARCH
  // ============================

  const getAnswer = (sectionNo, questionIndex) => {

    const key =
      `${sectionNo}_${questionIndex}`;

    return submission.answers.find(

      (item) =>
        item.questionNo === key

    );

  };

  // ============================
  // FILE TYPE
  // ============================

  const renderAnswer = (value) => {

    if (!value) {

      return (

        <span
          style={{
            color: "#dc2626",
            fontWeight: "600"
          }}
        >
          Not Answered
        </span>

      );

    }

    if (
      value.endsWith(".jpg") ||
      value.endsWith(".jpeg") ||
      value.endsWith(".png")
    ) {

      return (

        <a
          href={`http://localhost:5000${value}`}
          target="_blank"
          rel="noreferrer"
        >

          <img
            src={`http://localhost:5000${value}`}
            alt=""
            style={{
              width: "110px",
              borderRadius: "8px",
              border: "1px solid #ddd"
            }}
          />

        </a>

      );

    }

    if (

      value.endsWith(".pdf") ||

      value.endsWith(".doc") ||

      value.endsWith(".docx")

    ) {

      return (

        <a
          href={`http://localhost:5000${value}`}
          target="_blank"
          rel="noreferrer"
          style={{
            color: "#2563eb",
            fontWeight: "600",
            textDecoration: "none"
          }}
        >

          📄 View File

        </a>

      );

    }

    return value;

  };

  // ============================
  // TOTAL QUESTIONS
  // ============================

  const totalQuestions =
    facultyQuestions.reduce(

      (total, section) =>

        total + section.questions.length,

      0

    );

  return (

    <DeanLayout>
      <button
  onClick={() => navigate(-1)}
  style={{
    position: "fixed",
    top: "90px",
    left: "50px",
    zIndex: "9999",

    width: "52px",
    height: "52px",

    borderRadius: "50%",

    border: "none",

    background: "#2563eb",

    color: "#fff",

    fontSize: "22px",

    fontWeight: "700",

    cursor: "pointer",

    boxShadow: "0 6px 18px rgba(0,0,0,.25)",

    transition: "0.25s"
  }}
  title="Back"
>

  ←

</button>

      <div
        style={{
          maxWidth: "1350px",
          margin: "0 auto",
          padding: "30px"
        }}
      >    

        {/* ============================
            PAGE TITLE
        ============================ */}

        <h1
          style={{
            color: "#1e3a8a",
            marginBottom: "25px"
          }}
        >
          Faculty Submission
        </h1>

        {/* ============================
            INFORMATION CARD
        ============================ */}

        <div
          style={{
            background: "#fff",
            borderRadius: "12px",
            padding: "25px",
            boxShadow: "0 2px 8px rgba(0,0,0,.08)",
            marginBottom: "35px"
          }}
        >

          <table
            style={{
              width: "100%",
              borderCollapse: "collapse"
            }}
          >

            <tbody>

              <InfoRow
                title="Faculty Name"
                value={submission.submittedByName}
              />

              <InfoRow
                title="Email"
                value={submission.submittedByEmail}
              />

              <InfoRow
                title="School"
                value={submission.school}
              />

              <InfoRow
                title="Department"
                value={submission.department}
              />

              <InfoRow
                title="Quarter"
                value={submission.quarter}
              />

              <InfoRow
                title="Total Questions"
                value={submission.totalQuestions || totalQuestions}
              />

              <InfoRow
                title="Answered Count"
                value={submission.answeredCount}
              />

              <InfoRow
                title="Unanswered Count"
                value={submission.unansweredCount}
              />

              <tr>

                <td
                  style={{
                    padding: "12px",
                    fontWeight: "700",
                    width: "240px"
                  }}
                >
                  Status
                </td>

                <td
                  style={{
                    padding: "12px"
                  }}
                >

                  <span
                    style={{
                      background:
                        submission.status === "Approved by HOD"
                          ? "#16a34a"
                          : "#dc2626",
                      color: "#fff",
                      padding: "6px 14px",
                      borderRadius: "20px",
                      fontWeight: "600"
                    }}
                  >
                    {submission.status}
                  </span>

                </td>

              </tr>

            </tbody>

          </table>

        </div>

        {/* ============================
            FACULTY QUESTIONS
        ============================ */}

        <h2
          style={{
            color: "#2563eb",
            marginBottom: "20px"
          }}
        >
          Faculty Questionnaire
        </h2>
                {facultyQuestions.map((section) => (

          <div
            key={section.sectionNo}
            style={{
              background: "#fff",
              borderRadius: "12px",
              marginBottom: "35px",
              boxShadow: "0 2px 8px rgba(0,0,0,.08)",
              overflow: "hidden"
            }}
          >

            {/* SECTION HEADER */}

            <div
              style={{
                background: "#2563eb",
                color: "#fff",
                padding: "16px 22px",
                fontSize: "20px",
                fontWeight: "700"
              }}
            >
              Section {section.sectionNo} : {section.sectionTitle}
            </div>

            <table
              style={{
                width: "100%",
                borderCollapse: "collapse"
              }}
            >

              <thead>

                <tr
                  style={{
                    background: "#dbeafe"
                  }}
                >

                  <th style={thStyle}>
                    Question No
                  </th>

                  <th style={thStyle}>
                    Question
                  </th>

                  <th style={thStyle}>
                    Answer
                  </th>

                </tr>

              </thead>

              <tbody>

                {section.questions.map((question, index) => {

                  const answerObj =
                    getAnswer(
                      section.sectionNo,
                      index
                    );

                  const value =
                    answerObj
                      ? answerObj.answer
                      : "";

                  return (

                    <tr
                      key={index}
                    >

                      <td style={tdStyle}>
                        {section.sectionNo}.{index + 1}
                      </td>

                      <td style={tdStyle}>

                        <div
                          style={{
                            fontWeight: "600",
                            marginBottom: "4px"
                          }}
                        >
                          {question.question}
                        </div>

                        <div
                          style={{
                            color: "#6b7280",
                            fontSize: "13px"
                          }}
                        >
                          {question.answerFormat}
                        </div>

                      </td>

                      <td style={tdStyle}>

                        {renderAnswer(value)}

                      </td>

                    </tr>

                  );

                })}

              </tbody>

            </table>

          </div>

        ))}
              </div>

    </DeanLayout>

  );

}

